import pymongo

# Connect to MongoDB
client = pymongo.MongoClient("mongodb://localhost:27017/")

# Select database
db = client["mydatabase"]

# Select collection
collection = db["mycollection"]

def execute_filter_expression(filter_expression):
    # Execute filter expression using $where operator
    result = collection.find({"$where": filter_expression})
    
    # Fetch all results from MongoDB
    data = list(result)
    
    return data

def main():
    # Get user-provided filter expression as a string
    filter_expression = input("Enter your JavaScript filter expression: ")
    
    try:
        # Execute the filter expression on MongoDB server
        result = execute_filter_expression(filter_expression)
        
        print("Filtering Results:")
        for item in result:
            print(item)
            
    except Exception as e:
        print(f"Error executing filter expression: {str(e)}")

if __name__ == "__main__":
    main()